import React from 'react';
import { motion, easeInOut } from 'framer-motion';

export type GolbyExpression = 
  | 'happy' 
  | 'thinking' 
  | 'surprised' 
  | 'puzzled' 
  | 'waving'
  | 'winking'
  | 'laughing'
  | 'excited';

export type GolbySize = 'sm' | 'md' | 'lg' | 'xl';

interface GolbyIconProps {
  expression?: GolbyExpression;
  size?: GolbySize;
  animate?: boolean;
  className?: string;
}

const sizeMap = {
  sm: 'w-8 h-8',
  md: 'w-12 h-12',
  lg: 'w-16 h-16',
  xl: 'w-24 h-24'
};

